score_by_grade = {'A+':96,'A':92,'A-':88}

def score(name, grade): return score_by_grade[grade] + (sum(ord(c) for c in name) % 3) - 1

def parse_bazi():
    rows=[]
    for line in BAZI_MD.read_text(encoding='utf-8').splitlines():
        if not line.startswith('| '): continue
        p=[x.strip() for x in line.strip('|').split('|')]
        if p[0] in ('序号','---:') or len(p)<15: continue
        rows.append({'index':int(p[0]),'date':p[1],'time':p[2],'shichen':p[3],'year':p[4],'month':p[5],'day':p[6],'hour':p[7],'bazi':p[8],'jin':int(p[9]),'mu':int(p[10]),'shui':int(p[11]),'huo':int(p[12]),'tu':int(p[13]),'pattern':p[14] + ('格' if not p[14].endswith('格') else '')})
    return rows

def parse_names():
    rows=[]; gender=None; pattern=None
    for line in NAMES_MD.read_text(encoding='utf-8').splitlines():
        if line.startswith('# 男孩名字库'): gender='男'; continue
        if line.startswith('# 女孩名字库'): gender='女'; continue
        m=re.match(r'##\s+\d+\.\s+(.+?)（', line)
        if m: pattern=m.group(1).replace('男孩名','').replace('女孩名','').strip(); continue
        if line.startswith('| ') and not line.startswith('| 序号') and not line.startswith('|---'):
            p=[x.strip() for x in line.strip('|').split('|')]
            if len(p)==5 and gender and pattern:
                r={'gender':gender,'pattern':pattern,'index':int(p[0]),'name':p[1],'pinyin':p[2],'grade':p[3],'note':p[4]}
                n1,n2=r['name'][1],r['name'][2]
                m1=char_meta.get(n1,['未定','字义待补','常用取名义']); m2=char_meta.get(n2,['未定','字义待补','常用取名义'])
                r['score']=score(r['name'], r['grade']); r['wuxing']=f"白（金） + {n1}（{m1[0]}） + {n2}（{m2[0]}）"; r['meaning']=f"{n1}主{m1[1]}；{n2}主{m2[1]}。组合起来偏向“{r['note']}”。"; r['source']=f"{n1}取意：{m1[2]}；{n2}取意：{m2[2]}。"; r['reason']=f"评分 {r['score']}分：姓白按金性参考，后两字分别落在{m1[0]}、{m2[0]}，与{r['pattern']}的命名方向“{pattern_direction[r['pattern']]}”相容；再结合音律、字义、古风气质与长期使用稳定性综合给分。"
                rows.append(r)
    return rows

